export const deployATokenMock = async (
  incentivesController: string,
  slug: string,
  decimals = 18
): Promise<ATokenMock> => {
  const { deployer } = await hre.getNamedAccounts();
  const artifact = await hre.deployments.deploy(`${slug}-ATokenMock`, {
    contract: 'ATokenMock',
    from: deployer,
    args: [incentivesController, decimals],
    log: true,
  });
  return hre.ethers.getContractAt(artifact.abi, artifact.address);
};

export function getArtifact(contract: string): Artifact {
  let artifactsPath: string;
  if (!contract.includes('/')) {
    artifactsPath = path.resolve('./artifacts');
  } else {
    const packageName = `@balancer-labs/${contract.split('/')[0]}`;
    const packagePath = path.dirname(require.resolve(`${packageName}/package.json`));
    artifactsPath = `${packagePath}/artifacts`;
  }

  const artifacts = new Artifacts(artifactsPath);
  return artifacts.readArtifactSync(contract.split('/').slice(-1)[0]);
}

export function notEmitted(receipt: ContractReceipt, eventName: string): void {
  if (receipt.events != undefined) {
    const events = receipt.events.filter((e) => e.event === eventName);
    expect(events.length > 0).to.equal(false, `'${eventName}' event found`);
  }
}

