export function eventChecker(event: Event, name: string, args: any[] = []): void {
  expect(event.event).to.be.equal(name, `Incorrect event emitted`);
  expect(event.args?.length || 0 / 2).to.be.equal(args.length, `${name} signature are wrong`);
  args.forEach((arg, index) => {
    expect(event.args && event.args[index].toString()).to.be.equal(
      arg.toString(),
      `${name} has incorrect value on position ${index}`
    );
  });
}

export function getLinearCumulatedRewards(
  emissionPerSecond: BigNumberValue,
  lastUpdateTimestamp: BigNumberValue,
  currentTimestamp: BigNumberValue
): BigNumber {
  const timeDelta = valueToZDBigNumber(currentTimestamp).minus(lastUpdateTimestamp.toString());
  return timeDelta.multipliedBy(emissionPerSecond.toString());
}

export function getRewards(
  balance: BigNumberValue,
  assetIndex: BigNumberValue,
  userIndex: BigNumberValue,
  precision: number = 18
): BigNumber {
  return BigNumber.from(
    valueToZDBigNumber(balance)
      .multipliedBy(valueToZDBigNumber(assetIndex).minus(userIndex.toString()))
      .dividedBy(valueToZDBigNumber(10).exponentiatedBy(precision))
      .toString()
  );
}

